prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo (COUNT(DISTINCT ?pg) AS ?parallelGateways) (COUNT(DISTINCT ?flows) AS ?sequenceFlows) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?mid .
  FILTER(?mid = "1f1b01e0a85340689b6df314b32bb4b6")
  OPTIONAL { ?model bbo:name ?modelName . }
  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .
  OPTIONAL {
    ?pg a bboExt:ParallelGateway ;
        tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?flows a bbo:SequenceFlow ;
           tai:belongsTo ?choreo .
  }
}
GROUP BY ?model ?modelName ?choreo
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?midNorm ?midOrig ?choreo (COUNT(DISTINCT ?pg) AS ?parallelGateways) (COUNT(DISTINCT ?andPg) AS ?andGateways) (COUNT(DISTINCT ?sequenceFlows) AS ?sequenceFlows) WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?midNorm . }
  OPTIONAL { ?model tai:originalId ?midOrig . }
  FILTER(
    (BOUND(?midNorm) && LCASE(STR(?midNorm)) = LCASE("1f1b01e0a85340689b6df314b32bb4b6"))
    ||
    (BOUND(?midOrig) && LCASE(STR(?midOrig)) = LCASE("1f1b01e0a85340689b6df314b32bb4b6"))
  )
  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .
  OPTIONAL { ?pg a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?andPg a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?sequenceFlows a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName ?midNorm ?midOrig ?choreo
LIMIT 25

