prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?midNorm ?midOrig WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?midNorm . }
  OPTIONAL { ?model tai:originalId ?midOrig . }
  FILTER(
    (
      BOUND(?midNorm) && CONTAINS(LCASE(STR(?midNorm)), LCASE("1f1b01e0a85340689b6df314b32bb4b6"))
    )
    ||
    (
      BOUND(?midOrig) && CONTAINS(LCASE(STR(?midOrig)), LCASE("1f1b01e0a85340689b6df314b32bb4b6"))
    )
    ||
    (
      CONTAINS(LCASE(STR(?modelName)), LCASE("1f1b01e0a85340689b6df314b32bb4b6"))
    )
    ||
    (
      EXISTS {
        ?model ?p ?v .
        FILTER(CONTAINS(LCASE(STR(?v)), LCASE("1f1b01e0a85340689b6df314b32bb4b6")))
      }
    )
  )
}
LIMIT 25

