prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?container ?containerType ?containerName
       (COUNT(DISTINCT ?pg) AS ?parallelGateways)
       (COUNT(DISTINCT ?sf) AS ?sequenceFlows)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  ?container tai:belongsTo ?model .
  ?container a ?containerType .
  FILTER(?containerType IN (bboExt:Choreography, bboExt:Collaboration))
  OPTIONAL { ?container bbo:name ?containerName . }
  OPTIONAL { ?pg a bboExt:ParallelGateway ; tai:belongsTo ?container . }
  OPTIONAL { ?sf a bbo:SequenceFlow ; tai:belongsTo ?container . }
}
GROUP BY ?container ?containerType ?containerName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?def ?defType ?defName
       (COUNT(DISTINCT ?pg) AS ?parallelGateways)
       (COUNT(DISTINCT ?sf) AS ?sequenceFlows)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  ?def tai:belongsTo ?model .
  OPTIONAL { ?def bbo:name ?defName . }
  BIND(TYPE(?def) AS ?defType)
  OPTIONAL {
    ?pg a bboExt:ParallelGateway ; tai:belongsTo+ ?def .
  }
  OPTIONAL {
    ?sf a bbo:SequenceFlow ; tai:belongsTo+ ?def .
  }
}
GROUP BY ?def ?defType ?defName
LIMIT 25

