prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?def ?defType ?defName
       (COUNT(DISTINCT ?pg) AS ?parallelGateways)
       (COUNT(DISTINCT ?sf) AS ?sequenceFlows)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  ?def tai:belongsTo ?model .
  ?def a ?defType .
  OPTIONAL { ?def bbo:name ?defName . }
  OPTIONAL {
