prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?pg ?pgId ?pgName ?def
       ?inSrc ?inName
       ?outTgt ?outName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  ?def tai:belongsTo ?model .
  ?pg a bboExt:ParallelGateway ; tai:belongsTo ?def .
  OPTIONAL { ?pg bbo:id ?pgId . }
  OPTIONAL { ?pg bbo:name ?pgName . }
  OPTIONAL {
    ?sfIn a bbo:SequenceFlow ;
          bbo:has_targetRef ?pg ;
          tai:belongsTo ?def .
    ?sfIn bbo:has_sourceRef ?inSrc .
    OPTIONAL { ?inSrc bbo:name ?inName . }
  }
  OPTIONAL {
    ?sfOut a bbo:SequenceFlow ;
           bbo:has_sourceRef ?pg ;
           tai:belongsTo ?def .
    ?sfOut bbo:has_targetRef ?outTgt .
    OPTIONAL { ?outTgt bbo:name ?outName . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?pg ?pgId ?pgName
       ?src ?srcName
       ?tgt ?tgtName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  ?def tai:belongsTo ?model .
  ?pg a bboExt:ParallelGateway ; tai:belongsTo ?def .
  OPTIONAL { ?pg bbo:id ?pgId . }
  OPTIONAL { ?pg bbo:name ?pgName . }

  {
    ?sf a bbo:SequenceFlow ;
        bbo:has_targetRef ?pg ;
        bbo:has_sourceRef ?src .
  }
  UNION
  {
    ?sf a bbo:SequenceFlow ;
        bbo:has_sourceRef ?pg ;
        bbo:has_targetRef ?tgt .
  }

  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }

  FILTER(
    EXISTS { ?src tai:belongsTo+ ?def }
    ||
    EXISTS { ?tgt tai:belongsTo+ ?def }
  )
}
LIMIT 25

